/** Evaluate the arguments of a PrimFun application. */
private JamVal[] evalArgs() {
  JamVal[] values = new JamVal[args.length];
  for (int i = 0; i < args.length; i++) {
    values[i] = args[i].accept(evalVisitor);
  }
  return values;
}

/* Visitor methods. */
public JamVal forJamClosure(JamClosure closure) {
  Map code = closure.code();
  Variable[] params = code.vars();
  if (params.length != args.length) {
    throw new EvalException("Closure " + code + " expects " + params.length +
                           " arguments but was given " + args.length);
  }
  PureList<Binding> closureEnv = closure.env();
  PureList<Binding> newEnv = closureEnv;
  EvalVisitor newVisitor = evalVisitor.newVisitor(closureEnv);
  for (int i = 0; i < params.length; i++) {
    Binding binding = newVisitor.newBinding(params[i], args[i]);
    newEnv = newEnv.cons(binding);
    newVisitor = newVisitor.newVisitor(newEnv);
  }
  return code.body().accept(newVisitor);
}

public JamVal forPrimFun(PrimFun primFun) {
  JamVal[] values = evalArgs();
  StandardPrimFunVisitor spfv = new StandardPrimFunVisitor(values);
  return primFun.accept(spfv);
}

