  if (!(vals[0] instanceof JamFun)) {
    throw new EvalException("Primitive function `arity' applied to non-function " + vals[0]);
  }
  JamFun fun = (JamFun) vals[0];
  if (fun instanceof JamClosure) {
    JamClosure closure = (JamClosure) fun;
    return new IntConstant(closure.code().vars().length);
  } else if (fun instanceof PrimFun) {
    PrimFun primFun = (PrimFun) fun;
    String name = primFun.name();
    // Most primitive functions are unary
    if (name.equals("function?") || name.equals("number?") || name.equals("list?") ||
        name.equals("cons?") || name.equals("empty?") || name.equals("arity") ||
        name.equals("first") || name.equals("rest")) {
      return new IntConstant(1);
