import junit.framework.TestCase;
import java.io.StringReader;

/**
 * Comprehensive unit tests for the Jam interpreter implementation.
 * Tests cover all three evaluation strategies: call-by-value, call-by-name, and call-by-need.
 */
public class InterpreterAgentTest extends TestCase {

  public InterpreterAgentTest(String name) {
    super(name);
  }

  // ============ Helper Methods ============

  private void valueCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-value " + name, answer, interp.callByValue().toString());
  }

  private void nameCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-name " + name, answer, interp.callByName().toString());
  }

  private void needCheck(String name, String answer, String program) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals("by-need " + name, answer, interp.callByNeed().toString());
  }

  private void allCheck(String name, String answer, String program) {
    valueCheck(name, answer, program);
    nameCheck(name, answer, program);
    needCheck(name, answer, program);
  }

  private void valueThrowsCheck(String name, String program) {
    try {
      Interpreter interp = new Interpreter(new StringReader(program));
      interp.callByValue();
      fail("by-value " + name + " should throw EvalException");
    } catch (EvalException e) {
      // Expected
    }
  }

  private void nameThrowsCheck(String name, String program) {
    try {
      Interpreter interp = new Interpreter(new StringReader(program));
      interp.callByName();
      fail("by-name " + name + " should throw EvalException");
    } catch (EvalException e) {
      // Expected
    }
  }

  private void needThrowsCheck(String name, String program) {
    try {
      Interpreter interp = new Interpreter(new StringReader(program));
      interp.callByNeed();
      fail("by-need " + name + " should throw EvalException");
    } catch (EvalException e) {
      // Expected
    }
  }

  // ============ Constant Tests ============

  public void testIntegerConstant() {
    allCheck("intConstant", "42", "42");
    allCheck("negativeInt", "-100", "-100");
    allCheck("zero", "0", "0");
  }

  public void testBooleanConstant() {
    allCheck("boolTrue", "true", "true");
    allCheck("boolFalse", "false", "false");
  }

  public void testEmptyConstant() {
    allCheck("empty", "()", "empty");
  }

  // ============ Unary Operator Tests ============

  public void testUnaryPlus() {
    allCheck("unaryPlus", "42", "+ 42");
    allCheck("unaryPlusFive", "5", "+ 5");
  }

  public void testUnaryMinus() {
    allCheck("unaryMinus", "-42", "- 42");
    allCheck("unaryMinusNeg", "42", "- (- 42)");
  }

  public void testUnaryTilde() {
    allCheck("tildeFalse", "true", "~ false");
    allCheck("tildeTrue", "false", "~ true");
    allCheck("doubleNegate", "true", "~ (~ true)");
  }

  public void testUnaryOpTypeErrors() {
    valueThrowsCheck("unaryPlusOnBool", "+ true");
    valueThrowsCheck("unaryMinusOnBool", "- true");
    valueThrowsCheck("unaryTildeOnInt", "~ 42");
  }

  // ============ Binary Arithmetic Operator Tests ============

  public void testBinaryPlus() {
    allCheck("plus2and3", "5", "2 + 3");
    allCheck("plusWithNegative", "-1", "5 + (- 6)");
    allCheck("plusZero", "42", "42 + 0");
  }

  public void testBinaryMinus() {
    allCheck("minus5and3", "2", "5 - 3");
    allCheck("minusNegative", "11", "5 - (- 6)");
  }

  public void testBinaryTimes() {
    allCheck("times2and3", "6", "2 * 3");
    allCheck("timesZero", "0", "42 * 0");
    allCheck("timesNegative", "-6", "2 * (- 3)");
  }

